<?php

namespace App\Helpers;
use Illuminate\Support\Facades\Auth;
use App\Helpers\Menu\AdminMenu;
use App\Helpers\Menu\AuditorMenu;
use App\Helpers\Menu\ProdiMenu;

class MenuHelper
{
    public static function getGlobalItems()
    {
        return [

            [
                'type' => 'logout',
                'name' => 'Sign out',
                'icon' => 'logout',
            ],

        ];
    }

    public static function getMenuGroups()
    {
        if (!Auth::check()) {
            return [];
        }

        $user = Auth::user();

        $menuItems = [];
        $otherItems = [];

        switch ($user->role) {

            case 'admin':
                $menuItems = AdminMenu::get();
                $otherItems = AdminMenu::getOthers();
                break;

            case 'auditor':
            case 'unit_kerja':
                $menuItems = AuditorMenu::get();
                break;

            case 'prodi':
                $menuItems = ProdiMenu::get();
                break;

            default:
                $menuItems = [];
                $otherItems = [];
                break;
        }

        // tambahkan global menu
        $otherItems = array_merge(
            $otherItems,
            self::getGlobalItems()
        );

        return [

            [
                'title' => 'Menu',
                'items' => $menuItems
            ],

            [
                'title' => 'Lainnya',
                'items' => $otherItems
            ]

        ];
    }

    public static function isActive($path)
    {
        return request()->is(ltrim($path, '/'));
    }

